		// Daftar alat yang benar (sesuai permintaan kakak)
		var alatBenarArr1 = [
			_this.tabung_reaksi1, 
			_this.tabung_reaksi2, 
			_this.gula, 
			_this.penutup_tabung1, 
			_this.penutup_tabung2
		];
		
		// Alat salah (jika ada, tambahkan di sini)
		var alatSalahArr1 = []; 
		var semuaAlat1 = alatBenarArr1.concat(alatSalahArr1);
		
		var totalBenar1 = alatBenarArr1.length;
		var alatDiMeja1 = [];
		
		// Sembunyikan tombol Next di awal
		if(_this.btnNext1) _this.btnNext1.visible = false;
		
		// ----------------------- LOGIKA DRAG & DROP ----------------------------
		
		semuaAlat1.forEach(function(alat) {
			if (!alat) return;
		
			alat.startX = alat.x;
			alat.startY = alat.y;
			alat.diMeja = false;
			alat.cursor = "pointer";
		
			alat.removeAllEventListeners();
		
			// SAAT KLIK
			alat.on("mousedown", function(evt) {
				this.parent.addChild(this); // Bawa ke depan agar tidak tertutup
				this.offset = {x: this.x - evt.stageX, y: this.y - evt.stageY};
			});
		
			// SAAT GESER
			alat.on("pressmove", function(evt) {
				this.x = evt.stageX + this.offset.x;
				this.y = evt.stageY + this.offset.y;
			});
		
			// SAAT LEPAS (DROP)
			alat.on("pressup", function(evt) {
				// Cek apakah dilepas di atas meja (Instance Name: meja1_mc)
				var pt = _this.meja1_mc.globalToLocal(evt.stageX, evt.stageY);
				
				if (_this.meja1_mc.hitTest(pt.x, pt.y)) {
					// Jika alat BENAR
					if (alatBenarArr1.indexOf(this) != -1) {
						if (!this.diMeja) {
							this.diMeja = true;
							alatDiMeja1.push(this);
							
							// Kunci posisi alat di meja
							this.removeAllEventListeners();
							this.cursor = "default";
							
							// Animasi kecil saat diletakkan agar terasa "pas"
							createjs.Tween.get(this).to({scale:1.1}, 100).to({scale:1}, 100);
						}
						
						// Cek apakah 5 alat sudah lengkap di meja
						if (alatDiMeja1.length === totalBenar1) {
							if(_this.btnNext1) _this.btnNext1.visible = true;
						}
					} else {
						// Alat salah, balik ke rak
						this.x = this.startX;
						this.y = this.startY;
					}
				} else {
					// Lepas di luar meja, balik ke rak
					this.x = this.startX;
					this.y = this.startY;
				}
			});
		});
		
