	this.frame_11 = function() {
		this.stop();
		var root = this; // Menyimpan referensi ke Timeline utama
		
		// 1. HITUNG DATA AKHIR
		var totalSoal = window.soalAcak.length;
		var jumlahBenar = window.skorBenar || 0;
		var jumlahSalah = totalSoal - jumlahBenar;
		
		// Rumus Nilai
		var skorAkhir = Math.round((jumlahBenar / totalSoal) * 100);
		
		// 2. TAMPILKAN KE TEXT FIELD
		if (this.txt_benar) {
		    this.txt_benar.text = String(jumlahBenar);
		}
		
		if (this.txt_salah) {
		    this.txt_salah.text = String(jumlahSalah);
		}
		
		if (this.txt_nilai) {
		    this.txt_nilai.text = String(skorAkhir);
		}
		
		// 3. TOMBOL RESTART
		if (this.btn_ulang) {
		    this.btn_ulang.cursor = "pointer";
		    
		    // Gunakan 'root' di sini, bukan 'this'
		    this.btn_ulang.on("click", function() {
		        // Reset semua data
		        window.indeks = 0;
		        window.skorBenar = 0;
		        window.jawabanUser = "";
		        
		        // --- PERBAIKAN DI SINI ---
		        root.gotoAndStop("awal"); // Menggunakan referensi root
		        // -------------------------
		    });
		}
	}

